function readFile(name: string): Uint8Array {
  const handle = openSync(name, 'r');
  if (handle < 0) iError(`Couldn't read file ${name}`);
  const stat = fstatSync(handle);
  const buf = new Uint8Array(stat.size);
  const count = readSync(handle, buf);
  closeSync(handle);
  if (count < stat.size) iError(`Couldn't read file ${name}`);
  return buf;
}
